void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret=GetBlur1(vUv);
ret+=GetBlur1(vec2(vUv.x+ret.x,vUv.y+ret.y));
ret+=GetBlur1(vec2(vUv.x-ret.y,vUv.y-ret.y));
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
